  `ip_address` varchar(45) NOT NULL,
  `attempt_timestamp` timestamp NOT NULL DEFAULT current_timestamp(),
  `failure_reason` varchar(255) DEFAULT NULL,
  `is_blocked` tinyint(1) DEFAULT 0,
  `block_until` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Track failed login attempts for security and rate limiting';

