--
-- Table structure for table `login_activity`
--

CREATE TABLE `login_activity` (
  `id` bigint(20) UNSIGNED NOT NULL,
  `user_id` int(11) UNSIGNED DEFAULT NULL COMMENT 'References users.id',
  `email` varchar(255) NOT NULL,
  `login_timestamp` timestamp NOT NULL DEFAULT current_timestamp(),
  `login_status` enum('success','failed','blocked') NOT NULL DEFAULT 'success',
  `failure_reason` varchar(255) DEFAULT NULL COMMENT 'SMTP error, invalid credentials, etc',
  `ip_address` varchar(45) DEFAULT NULL COMMENT 'IPv4 or IPv6',
  `user_agent` text DEFAULT NULL COMMENT 'Browser/Client information',
  `session_id` varchar(64) DEFAULT NULL COMMENT 'PHP session ID for tracking',
  `device_fingerprint` varchar(64) DEFAULT NULL COMMENT 'For device recognition',
  `location_country` varchar(100) DEFAULT NULL,
  `location_city` varchar(100) DEFAULT NULL,
  `is_suspicious` tinyint(1) DEFAULT 0 COMMENT 'Flagged for unusual activity',
  `logout_timestamp` timestamp NULL DEFAULT NULL,
  `session_duration` int(11) DEFAULT NULL COMMENT 'Session duration in seconds'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Stores all login attempts and session activity';

