--
-- Table structure for table `sent_emails_new`
--

CREATE TABLE `sent_emails_new` (
  `id` bigint(20) UNSIGNED NOT NULL,
  `email_uuid` varchar(36) NOT NULL,
  `message_id` varchar(255) DEFAULT NULL,
  `sender_email` varchar(255) NOT NULL,
  `sender_name` varchar(255) DEFAULT NULL,
  `recipient_email` varchar(255) NOT NULL,
  `cc_list` text DEFAULT NULL COMMENT 'Comma-separated CC emails',
  `bcc_list` text DEFAULT NULL COMMENT 'Comma-separated BCC emails',
  `reply_to` varchar(255) DEFAULT NULL,
  `subject` varchar(500) NOT NULL,
  `article_title` varchar(500) DEFAULT NULL,
  `body_text` longtext DEFAULT NULL COMMENT 'Plain text version',
  `body_html` longtext DEFAULT NULL COMMENT 'HTML formatted body',
  `label_id` int(10) UNSIGNED DEFAULT NULL,
  `label_name` varchar(100) DEFAULT NULL,
  `label_color` varchar(7) DEFAULT NULL COMMENT 'Hex color code',
  `has_attachments` tinyint(1) DEFAULT 0,
  `email_type` enum('sent','draft') DEFAULT 'sent',
  `is_deleted` tinyint(1) DEFAULT 0,
  `sent_at` timestamp NULL DEFAULT current_timestamp(),
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

